import{r as e}from"./rolldown-runtime-QTnfLwEv.js";import{n as t,t as n}from"./vendor-react-CIxEorsV.js";import{n as r}from"./vendor-router-XxCI5KMz.js";import"./useMeta-Ci6jPQUv.js";import{t as i}from"./SeoPage.module-DkyBZNHX.js";var a=e(t(),1),o=n();function s(){return(0,a.useEffect)(()=>{document.title=`Football Player Rating System | How to Rate Football Players | Veyro`;let e={"@context":`https://schema.org`,"@type":`Article`,headline:`Football Player Rating System: How to Rate Players After Every Game`,description:`A complete guide to rating football players by position — QB, RB, WR, TE, OL, DL, LB, DB — using stat-based formulas.`,author:{"@type":`Organization`,name:`Veyro`},publisher:{"@type":`Organization`,name:`Veyro`,url:`https://darksalmon-lark-983637.hostingersite.com`},datePublished:`2026-06-01`,dateModified:`2026-06-01`,mainEntityOfPage:{"@type":`WebPage`,"@id":`https://darksalmon-lark-983637.hostingersite.com/football-rating-system`}},t=document.createElement(`script`);return t.type=`application/ld+json`,t.text=JSON.stringify(e),document.head.appendChild(t),()=>document.head.removeChild(t)},[]),(0,o.jsx)(`main`,{className:i.seoPage,children:(0,o.jsxs)(`article`,{children:[(0,o.jsxs)(`section`,{className:i.hero,children:[(0,o.jsx)(`div`,{className:i.eyebrow,children:`Football Analytics`}),(0,o.jsx)(`h1`,{className:i.h1,children:`How to rate football players after every game.`}),(0,o.jsx)(`p`,{children:`Rating football players is more position-specific than almost any other sport. A quarterback's game is almost entirely about passing efficiency. An offensive lineman's game may produce zero stats in a traditional box score while being the most important player on the field. A safety's game is invisible until something goes wrong. Building a fair rating system means building a different formula for every position.`}),(0,o.jsxs)(`div`,{className:i.actions,children:[(0,o.jsx)(r,{className:i.button,to:`/football`,children:`Try Football Calculator`}),(0,o.jsx)(r,{className:i.button,to:`/football/vault`,children:`Football Vault`})]})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`Rating quarterbacks.`}),(0,o.jsx)(`p`,{children:`The quarterback is the most analyzed position in American sports. Passing yards, touchdowns, interceptions, completion percentage, and yards per attempt are the foundation. But passer rating formulas have existed since the 1970s and they all agree on one thing: touchdowns and interceptions carry more weight than yardage because they directly determine scoring and possession.`}),(0,o.jsx)(`p`,{children:`The Veyro QB formula starts at a base of 66 and adds for passing yards per snap, touchdowns, and completions, then heavily subtracts for interceptions. A QB who throws for 280 yards, 2 touchdowns, and 0 interceptions on 60 snaps will rate well above 80. A QB who throws for 320 yards but with 3 interceptions may rate below 70 despite the impressive yardage.`}),(0,o.jsxs)(`div`,{className:i.grid,children:[(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Passing yards`}),(0,o.jsx)(`span`,{children:`Weighted by snaps played. A QB who produces 5 yards per snap is performing above average.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Touchdowns`}),(0,o.jsx)(`span`,{children:`High weight. Each TD adds significantly to the rating. Touchdowns win games.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Interceptions`}),(0,o.jsx)(`span`,{children:`High negative weight. Each interception subtracts significantly more than a touchdown adds.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Completions`}),(0,o.jsx)(`span`,{children:`Moderate weight. Completion rate is a proxy for decision making and accuracy under pressure.`})]})]})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`Rating running backs.`}),(0,o.jsx)(`p`,{children:`Running backs are rated on rushing yards per snap and rushing touchdowns, with secondary credit for receptions and receiving yards when they are used as pass catchers. A RB who carries the ball 18 times for 112 yards and a touchdown is having a strong game. A RB who carries the ball 22 times for 64 yards and fumbles once is having a poor game regardless of the volume.`}),(0,o.jsx)(`p`,{children:`Fumbles are the most damaging stat for a running back rating because they directly transfer possession. A single fumble can lower a rating by 10-15 points depending on the overall performance level.`})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`Rating wide receivers and tight ends.`}),(0,o.jsx)(`p`,{children:`WRs and TEs are rated on receiving yards per snap, receptions, and receiving touchdowns. The formula accounts for the fact that receivers are dependent on quarterback decisions and offensive play-calling — a receiver who runs perfect routes but receives no targets should not be rated poorly for their work.`}),(0,o.jsx)(`p`,{children:`The most useful secondary stat for receivers is separation — how far they get from coverage on their routes. This is not always available at youth and amateur level, but when it is, it tells the full story of a receiver's performance regardless of targets.`})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`Rating defensive players.`}),(0,o.jsx)(`p`,{children:`Defense is the hardest side of football to rate because most defensive impact is invisible until it goes wrong. A linebacker who makes perfect reads and forces the offense into an incompletion on third down will not appear in the box score. The stats that do appear — tackles, sacks, forced fumbles, interceptions, and defensive touchdowns — heavily favor defensive linemen and linebackers over safeties and corners who may be doing excellent work in coverage without touches.`}),(0,o.jsxs)(`div`,{className:i.grid,children:[(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Defensive linemen`}),(0,o.jsx)(`span`,{children:`Rate on tackles, sacks, and pressures. A DL with 2 sacks and 4 tackles is having an excellent game. Forced fumbles add significantly.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Linebackers`}),(0,o.jsx)(`span`,{children:`Rate on tackles first, then sacks, forced fumbles, and interceptions. LBs are expected to produce tackles consistently.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Defensive backs`}),(0,o.jsx)(`span`,{children:`Rate on interceptions, pass breakups, and tackles in run support. Coverage quality is genuinely hard to capture in basic stats.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Defensive touchdowns`}),(0,o.jsx)(`span`,{children:`The highest-value defensive play. A pick-six or fumble return for a touchdown adds maximum points to the rating.`})]})]})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`Position base scores in the Veyro formula.`}),(0,o.jsx)(`p`,{children:`The Veyro football rating formula uses position-specific base scores that reflect the typical difficulty and visibility of each role. Quarterbacks start at 66 because their performance is highly visible and directly measurable. Offensive linemen start at 63 because their contribution is real but harder to quantify. Kickers start at 62 because their opportunities are infrequent and results binary.`}),(0,o.jsxs)(`div`,{className:i.grid,children:[(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`QB: 66`}),(0,o.jsx)(`span`,{children:`High visibility, high accountability, high impact on game outcome.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`WR: 65`}),(0,o.jsx)(`span`,{children:`Production depends partly on QB decisions, but route running and catch quality are player-controlled.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`RB: 64`}),(0,o.jsx)(`span`,{children:`Direct production through carries and catches. More controllable than WR.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`TE: 64`}),(0,o.jsx)(`span`,{children:`Hybrid role between blocker and receiver. Blocking contribution is hard to capture.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`LB / DB: 64`}),(0,o.jsx)(`span`,{children:`Tackling and coverage contributions weighted appropriately.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`OL / DL: 63`}),(0,o.jsx)(`span`,{children:`Trench play has enormous impact but limited statistical capture.`})]})]})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`FAQ.`}),(0,o.jsxs)(`div`,{className:i.grid,children:[(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Can I use this for flag football?`}),(0,o.jsx)(`span`,{children:`Yes. The same positions and stats apply. The key difference is that sacks and physical tackling stats will not appear, but passing, rushing, and receiving stats work identically.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`How do I rate an offensive lineman with no stats?`}),(0,o.jsx)(`span`,{children:`Use the snap count as the primary input and note penalties and sacks allowed in the match notes. Until the formula has a penalties-allowed input, OL ratings will be approximate.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`What is a good rating for a high school QB?`}),(0,o.jsx)(`span`,{children:`Consistently above 75 is solid for a varsity QB. Above 85 is excellent. A QB averaging below 65 may be in the wrong system or facing a difficulty spike they need support with.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`How do I handle a two-way player?`}),(0,o.jsx)(`span`,{children:`Enter two separate ratings — one for each position — and average them if you want a single number. Tracking both gives a clearer picture of where the player contributes most.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Should I rate special teams?`}),(0,o.jsx)(`span`,{children:`Yes if the player has meaningful special teams snaps. Kicker accuracy (field goals made vs attempted) and punting average are straightforward to track. Return touchdowns are high-impact plays worth rating separately.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Can coaches use this for the whole team?`}),(0,o.jsxs)(`span`,{children:[`Yes. Use the `,(0,o.jsx)(r,{to:`/football`,children:`Veyro football calculator`}),` to rate each player after every game, then review team trends in the coach dashboard.`]})]})]})]})]})})}export{s as default};